    protected override async Task OnInitializedAsync()
    {
        // Reload company list from sessionStorage if missing
        if (CompanyService.Companies == null || !CompanyService.Companies.Any())
        {
            var json = await JS.InvokeAsync<string>("sessionStorage.getItem", "Companies");
            if (!string.IsNullOrEmpty(json))
            {
                try
                {
                    CompanyService.Companies = System.Text.Json.JsonSerializer.Deserialize<List<MobileCheckResponse>>(json);
                }
                catch { /* ignore errors */ }
            }
        }

        // Get or generate device ID
        DeviceId = await JS.InvokeAsync<string>("localStorage.getItem", "deviceId");
        if (string.IsNullOrEmpty(DeviceId))
        {
            DeviceId = await JS.InvokeAsync<string>("eval", "crypto.randomUUID ? crypto.randomUUID() : ([1e7]+-1e3+-4e3+-8e3+-1e11).replace(/[018]/g, c=>(c^crypto.getRandomValues(new Uint8Array(1))[0]&15>>c/4).toString(16))");
            await JS.InvokeVoidAsync("localStorage.setItem", "deviceId", DeviceId);
        }
    }

    private async Task HandleCompanyLogin()
    {
        if (CompanyService.SelectedCompany == null) return;

        IsLoading = true;
        Message = null;

        var request = new CompanyLoginRequest
        {
            CompanyCode = CompanyService.SelectedCompany.CompanyCode ?? "",
            CdyKey = CompanyService.SelectedCompany.LicenceKey ?? "",
            UserName = UserName ?? "",
            Password = Password ?? "",
            DeviceId = DeviceId ?? "TP1A.220624.014" // fallback if not set
        };

        var result = await AuthService.CompanyLoginAsync(request);
        if (result.Success)
        {
            IsSuccess = true;
            Message = "Login successful!";
            // Store userId and mobile number in session service
            await UserSession.SetUserIdAsync(result.UserId);
            // If you have mobile number available, set it here as well:
            // UserSession.MobileNo = ...;
            // Redirect to main page after login
            Navigation.NavigateTo("/sales", forceLoad: true);
        }
        else
        {
            IsSuccess = false;
            if (!string.IsNullOrEmpty(result.Message) && result.Message.Contains("already logged in on another device", System.StringComparison.OrdinalIgnoreCase))
            {
                Message = "You are already logged in on another device. Please logout from your previous device before logging in here.";
            }
            else
            {
                Message = result.Message;
            }
        }

        IsLoading = false;
    }

